size(7cm);
defaultpen(linewidth(0.7));
dotfactor=4;
int i,j;

fill((6,0)--(7,0)--(7,2)--(6,2)--cycle,gray);

for(i=0;i<=3;++i)

{

draw((i,0)--(i,2));

draw((i+5,0)--(i+5,2));

draw((i+10,0)--(i+10,2));

}
for(j=0;j<=2;++j)

{

draw((0,j)--(3.3,j));

draw((0,j)--(3.3,j));

draw((4.7,j)--(8.3,j));

draw((4.7,j)--(8.3,j));

draw((9.7,j)--(13,j));

draw((9.7,j)--(13,j));

}

real x;

for(x=3.7;x<=4.3;x=x+0.3)

{

dot((x,0));

dot((x,2));

dot((x+5,0));

dot((x+5,2));

}[/asy]
